vec2 p = vec2(u, v) * 8.0;

// --- DISTORSIONE (Domain Warping) ---
// Calcoliamo un valore di rumore base
float n1 = sys_noise(p);

// Usiamo il rumore per spostare le coordinate del passaggio successivo
// Questo crea l'effetto fluido/liquido
vec2 shift = vec2(n1, sys_noise(p + vec2(5.0, 5.0))); 

// --- PATTERN FINALE ---
// Calcoliamo il rumore finale sulle coordinate distorte
float pattern = sys_noise(p + shift * 2.0);

// --- CONTRASTO ---
// Rendiamo i bordi più netti (taglia i grigi intermedi)
pattern = smoothstep(0.3, 0.7, pattern);

